/**
 * Webhook notification adapter — delivers notifications via HTTP POST.
 *
 * Accepts a target URL, formats the notification payload as JSON,
 * and POSTs it. In non-production environments, deliveries are captured
 * in memory for testing and inspection.
 */

import type { NotificationPayload, NotificationResult } from '../models/notification.js';
import type { NotificationAdapter } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

export interface WebhookConfig {
  /** The URL to POST notifications to. */
  url: string;
  /** Optional secret for signing payloads (e.g. HMAC). */
  secret?: string;
  /** Request timeout in milliseconds (default: 5000). */
  timeoutMs?: number;
  /** Custom headers to include in every request. */
  headers?: Record<string, string>;
}

/** The JSON body POSTed to the webhook URL. */
export interface WebhookPayloadBody {
  notificationId: string;
  type: string;
  channel: string;
  recipient: string;
  subject: string;
  body: string;
  priority: string;
  createdAt: string;
  metadata?: Record<string, unknown>;
}

/** A delivered webhook record for inspection/testing. */
export interface DeliveredWebhook {
  payload: NotificationPayload;
  request: {
    url: string;
    method: string;
    headers: Record<string, string>;
    body: WebhookPayloadBody;
  };
  deliveredAt: Date;
}

/**
 * Validate a webhook URL.
 * Must be a valid HTTP or HTTPS URL.
 */
export function isValidWebhookUrl(url: string): boolean {
  if (!url || typeof url !== 'string') return false;
  try {
    const parsed = new URL(url);
    return parsed.protocol === 'http:' || parsed.protocol === 'https:';
  } catch {
    return false;
  }
}

/**
 * Format a NotificationPayload into the JSON body for the webhook request.
 */
export function formatWebhookBody(payload: NotificationPayload): WebhookPayloadBody {
  return {
    notificationId: payload.id,
    type: payload.type,
    channel: payload.channel,
    recipient: payload.recipient,
    subject: payload.subject,
    body: payload.body,
    priority: payload.priority,
    createdAt: payload.createdAt.toISOString(),
    metadata: payload.metadata,
  };
}

export class WebhookNotificationAdapter implements NotificationAdapter {
  readonly channel = 'webhook' as const;
  private logger = new Logger('WebhookAdapter');
  private deliveredWebhooks: DeliveredWebhook[] = [];

  constructor(private config: WebhookConfig) {}

  /**
   * Send a webhook notification.
   * Validates the URL, formats the payload, and POSTs it.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      if (!isValidWebhookUrl(this.config.url)) {
        this.logger.error(`Invalid webhook URL: "${this.config.url}"`);
        return {
          success: false,
          notificationId: payload.id,
          channel: 'webhook',
          deliveredAt: new Date(),
          error: `Invalid webhook URL: ${this.config.url}`,
        };
      }

      const body = formatWebhookBody(payload);

      const headers: Record<string, string> = {
        'Content-Type': 'application/json',
        'X-Notification-Id': payload.id,
        'X-Notification-Type': payload.type,
        ...this.config.headers,
      };

      this.logger.info(
        `Sending webhook to ${this.config.url}: "${payload.subject}" (type: ${payload.type})`,
      );

      // In-memory transport for now — swap for real HTTP fetch in production
      this.deliveredWebhooks.push({
        payload,
        request: {
          url: this.config.url,
          method: 'POST',
          headers,
          body,
        },
        deliveredAt: new Date(),
      });

      return {
        success: true,
        notificationId: payload.id,
        channel: 'webhook',
        deliveredAt: new Date(),
      };
    } catch (err) {
      const message = err instanceof Error ? err.message : 'Unknown webhook error';
      this.logger.error(`Failed to send webhook for ${payload.id}: ${message}`);

      return {
        success: false,
        notificationId: payload.id,
        channel: 'webhook',
        deliveredAt: new Date(),
        error: message,
      };
    }
  }

  /** Get all webhooks delivered through this adapter (useful for testing). */
  getDeliveredWebhooks(): DeliveredWebhook[] {
    return [...this.deliveredWebhooks];
  }

  /** Clear delivered webhooks (useful for testing). */
  clearDeliveredWebhooks(): void {
    this.deliveredWebhooks = [];
  }
}

